consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
.skeleton {
  background-color: var(--color-background-secondary);
  position: relative;
  overflow: hidden;
}

/* ─── Variants ──────────────────────────────────────────────────────────────── */

.text {
  height: 14px;
  border-radius: var(--dimension-radius-050);
  width: 100%;
}

.circular {
  width: 40px;
  height: 40px;
  border-radius: var(--dimension-radius-half);
}

.rectangular {
  width: 100%;
  height: 80px;
  border-radius: var(--dimension-radius-075);
}

/* ─── Text group ────────────────────────────────────────────────────────────── */

.textGroup {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-075);
}

/* ─── Shimmer animation ─────────────────────────────────────────────────────── */

.animate::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(
    90deg,
    transparent 0%,
    var(--color-interaction-hover) 50%,
    transparent 100%
  );
  animation: shimmer 1.5s ease-in-out infinite;
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import styles from './Skeleton.module.css';

export type SkeletonVariant = 'text' | 'circular' | 'rectangular';

export interface SkeletonProps {
  /** Shape of the skeleton. */
  variant?: SkeletonVariant;
  /** Width (CSS value). */
  width?: string | number;
  /** Height (CSS value). */
  height?: string | number;
  /** Number of text lines to render. Only applies to 'text' variant. */
  lines?: number;
  /** Whether to animate the shimmer. */
  animate?: boolean;
  className?: string;
}

export const Skeleton = forwardRef<HTMLDivElement, SkeletonProps>(
  (
    {
      variant = 'text',
      width,
      height,
      lines = 1,
      animate = true,
      className,
    },
    ref
  ) => {
    if (variant === 'text' && lines > 1) {
      return (
        <div ref={ref} className={cn(styles.textGroup, className)} style={{ width }}>
          {Array.from({ length: lines }, (_, i) => (
            <div
              key={i}
              className={cn(styles.skeleton, styles.text, animate && styles.animate)}
              style={{
                width: i === lines - 1 ? '60%' : '100%',
                height,
              }}
            />
          ))}
        </div>
      );
    }

    return (
      <div
        ref={ref}
        className={cn(
          styles.skeleton,
          styles[variant],
          animate && styles.animate,
          className
        )}
        style={{ width, height }}
        aria-hidden="true"
      />
    );
  }
);

Skeleton.displayName = 'Skeleton';
